/**
 * Unicode documentation example.
 * 
 * 🎉 This function celebrates with emoji! 🎉
 * 
 * 日本語のドキュメント
 * 中文文档
 * Korean: 한글 문서
 * 
 * @param {string} greeting - The greeting message
 * @returns {string} The processed greeting
 */
function unicodeExample(greeting) {
    return `✨ ${greeting} ✨`;
}
